-- Decode RLE into the MAP lookup table once at load time.
local MAP = {}
do
  local idx = 1
  for _, entry in ipairs(RLE) do
    local id, count = entry[1], entry[2]
    for _ = 1, count do
      MAP[idx] = id
      idx = idx + 1
    end
  end
end

--- Returns the shape ID at pixel (x, y).
--- x and y are 0-based. Returns 0 if out of bounds or no shape.
function shapes.get_shape(x, y)
  if x < 0 or x >= WIDTH or y < 0 or y >= HEIGHT then
    return 0
  end
  return MAP[y * WIDTH + x + 1] or 0
end

return shapes